// Process Ollama response
const body = $input.first().json || {};
const webhookInput = $input.all()[1]?.json || {};

const message = body.message?.content || '';
const model = body.model || webhookInput.model || 'unknown';
const done = body.done || false;
const evalCount = body.eval_count || 0;
const promptEvalCount = body.prompt_eval_count || 0;
const totalDuration = body.total_duration || 0;

// Convert nanoseconds to seconds for readability
const durationSec = (totalDuration / 1e9).toFixed(2);

return [{
  json: {
    success: done && !!message,
    model: model,
    response: message,
    tokens_used: evalCount + promptEvalCount,
    prompt_tokens: promptEvalCount,
    completion_tokens: evalCount,
    duration_seconds: durationSec,
    timestamp: new Date().toISOString(),
    channel: webhookInput.channel || 'general'
  }
}];

